/**
 * ActionButton component combines Button with ActionTooltip
 *
 * This component wraps a Button inside an ActionTooltip, providing
 * a convenient way to add tooltips to action buttons throughout the application.
 *
 * @param props - Component props
 * @param ref - Forwarded ref to the button element
 * @returns ActionButton component
 */
export interface ActionButtonProps extends Omit<ButtonButtonProps, 'className'> {
    children?: React.ReactNode;
    className?: string;
    tooltipTitle?: ActionTooltipProps['title'];
    tooltipPlacement?: ActionTooltipProps['placement'];
    tooltipDisabled?: ActionTooltipProps['disabled'];
    tooltipOpenDelay?: ActionTooltipProps['openDelay'];
    tooltipCloseDelay?: ActionTooltipProps['closeDelay'];
    wrapperClassName?: string;
}

export interface AlertProps {
    text: string;
    variant?: 'default' | 'warning' | 'error' | 'info';
    icon?: React.ReactNode;
    button?: {
        content: React.ReactNode;
        onClick: () => void;
    };
    content?: React.ReactNode;
    initialExpanded?: boolean;
    className?: string;
    qa?: string;
}

export type BaseMessageProps = {
    children: React.ReactNode;
    role: TMessageRole; // 'user' | 'assistant' | 'system'
    actions?: BaseMessageAction[];
    userRating?: UserRating; // 'like' | 'dislike'
    timestamp?: string;
    showTimestamp?: boolean;
    showActionsOnHover?: boolean;
    className?: string;
    qa?: string;
};

export type ButtonGroupProps = {
    orientation?: 'horizontal' | 'vertical';
    children: React.ReactNode;
    className?: string;
    qa?: string;
};

/**
 * ChatContainer - fully assembled chat component, the main exportable component of the library.
 * Integrates Header, ChatContent, History and manages their state.
 */
export interface ChatContainerProps {
    chats?: ChatType[];
    activeChat?: ChatType | null;
    messages?: TChatMessage[];
    onSendMessage: (data: TSubmitData) => Promise<void>;
    onSelectChat?: (chat: ChatType) => void;
    onCreateChat?: () => void;
    onDeleteChat?: (chat: ChatType) => void;
    onDeleteAllChats?: () => Promise<void>;
    onFold?: (value: 'collapsed' | 'opened') => void;
    onClose?: () => void;
    onCancel?: () => Promise<void>;
    status?: ChatStatus;
    error?: Error | null;
    showActionsOnHover?: boolean;
    onRetry?: () => void;
    contextItems?: ContextItemConfig[];
    transformOptions?: OptionsType;
    shouldParseIncompleteMarkdown?: boolean;
    messageListConfig?: MessageListConfig;
    headerProps?: Partial<Omit<HeaderProps, ...>>;
    contentProps?: Partial<Omit<ChatContentProps, ...>>;
    emptyContainerProps?: Partial<EmptyContainerProps>;
    promptInputProps?: Partial<Omit<PromptInputProps, ...>>;
    disclaimerProps?: Partial<DisclaimerProps>;
    historyProps?: Partial<Omit<HistoryProps, ...>>;
    welcomeConfig?: WelcomeConfig;
    i18nConfig?: ChatContainerI18nConfig;
    showHistory?: boolean;
    showNewChat?: boolean;
    showFolding?: boolean;
    showClose?: boolean;
    hideTitleOnEmptyChat?: boolean;
    className?: string;
    headerClassName?: string;
    contentClassName?: string;
    footerClassName?: string;
    qa?: string;
}

/**
 * Props for ChatContent component
 */
export interface ChatContentProps {
    /** Display mode: 'empty' - EmptyContainer, 'chat' - MessageList */
    view: ChatContentView; // 'empty' | 'chat'
    /** Props for EmptyContainer (used when view='empty') */
    emptyContainerProps?: EmptyContainerProps;
    /** Props for MessageList (used when view='chat') */
    messageListProps?: MessageListProps;
    /** Additional CSS class */
    className?: string;
    /** QA/test identifier */
    qa?: string;
}

/**
 * ChatDate component displays formatted dates with optional time
 */
export type ChatDateProps = QAProps & DOMProps & {
    /** Date value in string, Date, or number (timestamp) format */
    date: string | Date | number;
    /** Show time along with date */
    showTime?: boolean;
    /** Custom format string (dayjs format) */
    format?: string;
    /** Display relative dates (today, yesterday, two days ago, etc.) */
    relative?: boolean;
};

type CommonProps = {
    usedContext: number;
    className?: string;
    qa?: string;
    orientation?: 'horizontal' | 'vertical';
    reversed?: boolean;
};
type NumberProps = { type: 'number'; maxContext: number; } & CommonProps;
type PercentProps = { type: 'percent'; usedContext: number; } & CommonProps;
export type ContextIndicatorProps = NumberProps | PercentProps;

type ContextItemProps = QAProps & {
    content: React.ReactNode;
    onClick?: () => void;
    className?: string;
};

type DiffStatProps = DOMProps & QAProps & {
    added: number;
    deleted: number;
};
